def hamiltonian_path(graph, n):
    visited = [False] * n
    path = []

    def backtrack(v):
        if len(path) == n:
            return True  # All vertices visited

        for neighbor in graph[v]:
            if not visited[neighbor]:
                visited[neighbor] = True
                path.append(neighbor)

                if backtrack(neighbor):
                    return True

                # Backtrack
                path.pop()
                visited[neighbor] = False

        return False

    # Try starting from each vertex
    for start in range(n):
        visited[start] = True
        path.append(start)

        if backtrack(start):
            return path

        path.pop()
        visited[start] = False

    return None  # No Hamiltonian path exists

# Example: Graph with Hamiltonian path
# 0 -- 1 -- 2 -- 3
graph = {0: [1], 1: [0, 2], 2: [1, 3], 3: [2]}
result = hamiltonian_path(graph, 4)
print("Hamiltonian Path:", result)
